begin;
create table if not exists public.project_block_homologations(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,development_id uuid not null references public.developments(id) on delete cascade,status text not null check(status in('passed','revoked')),evidence_snapshot jsonb not null,approved_by uuid not null references public.profiles(id),approval_note text not null check(char_length(approval_note) between 10 and 500),approved_at timestamptz not null default now());
create index if not exists project_block_homologations_history_idx on public.project_block_homologations(organization_id,development_id,approved_at desc);alter table public.project_block_homologations enable row level security;drop policy if exists project_block_homologations_scope on public.project_block_homologations;create policy project_block_homologations_scope on public.project_block_homologations for select to authenticated using(organization_id=(select public.current_organization_id()));revoke all on public.project_block_homologations from anon;revoke insert,update,delete on public.project_block_homologations from authenticated;grant select on public.project_block_homologations to authenticated;
create or replace function public.approve_project_block_homologation(p_actor_id uuid,p_organization_id uuid,p_development_id uuid,p_evidence jsonb,p_note text)returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;target_id uuid;required_keys text[]:=array['developer','registry','catalog','inventory','commercialRelease','materials','regionStudy','aiDossier'];key text;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role<>'director'then raise exception 'project_homologation_director_required';end if;if char_length(trim(coalesce(p_note,'')))<10 then raise exception 'project_homologation_note_required';end if;if not exists(select 1 from public.developments d join public.developers v on v.id=d.developer_id and v.organization_id=d.organization_id and v.status='active'where d.id=p_development_id and d.organization_id=p_organization_id and d.name is not null and d.neighborhood is not null and d.city is not null and d.state is not null)then raise exception 'project_homologation_registry_incomplete';end if;if not exists(select 1 from public.development_typologies where development_id=p_development_id and organization_id=p_organization_id and status='active')then raise exception 'project_homologation_catalog_incomplete';end if;if not exists(select 1 from public.properties where development_id=p_development_id and organization_id=p_organization_id and typology_id is not null and price>=0)then raise exception 'project_homologation_inventory_incomplete';end if;if not exists(select 1 from public.development_commercial_releases where development_id=p_development_id and organization_id=p_organization_id and status='active'and valid_from<=now()and(valid_until is null or valid_until>now()))then raise exception 'project_homologation_release_incomplete';end if;if(select count(distinct material_type)from public.project_materials where development_id=p_development_id and organization_id=p_organization_id and is_current=true and review_status='verified'and material_type in('book','price_table','sales_mirror')and(valid_from is null or valid_from<=current_date)and(valid_until is null or valid_until>=current_date))<3 then raise exception 'project_homologation_materials_incomplete';end if;if(select count(*)from public.project_region_sources where development_id=p_development_id and organization_id=p_organization_id and review_status='verified'and valid_until>=current_date)<2 then raise exception 'project_homologation_region_incomplete';end if;if not exists(select 1 from public.project_intelligence_profiles where development_id=p_development_id and organization_id=p_organization_id and onboarding_status='published'and readiness_percent=100)then raise exception 'project_homologation_dossier_incomplete';end if;foreach key in array required_keys loop if coalesce((p_evidence->key->>'passed')::boolean,false)=false then raise exception 'project_homologation_snapshot_incomplete:%',key;end if;end loop;insert into public.project_block_homologations(organization_id,development_id,status,evidence_snapshot,approved_by,approval_note)values(p_organization_id,p_development_id,'passed',p_evidence,p_actor_id,trim(p_note))returning id into target_id;return jsonb_build_object('homologationId',target_id,'developmentId',p_development_id,'status','passed','gates',8,'serverRevalidated',true,'directorApproved',true,'snapshotPreserved',true,'productionAuthorized',false);end $$;
revoke all on function public.approve_project_block_homologation(uuid,uuid,uuid,jsonb,text)from public,anon,authenticated;grant execute on function public.approve_project_block_homologation(uuid,uuid,uuid,jsonb,text)to service_role;
commit;
